// Arma el mensaje de Telegram con el resumen
const d = $json;
let msg = '';
if (d.ok) {
  const r = d.resumen || {};
  msg += '\ud83d\udcc8 *TENDENCIAS DE CONTENIDO — ' + (r.mes||'') + ' ' + (r.anio||'') + '*\n\n';
  msg += '\u2705 Documento generado y subido a Drive\n';
  msg += '\ud83d\udcca ' + (r.totalTend||0) + ' tendencias en ' + (r.nichosConTend||0) + '/12 nichos\n\n';
  if (r.top5 && r.top5.length) {
    msg += '\u2b50 *Top 5 del mes:*\n';
    r.top5.forEach((t,i)=>{ msg += (i+1)+'. '+t.titulo+' _('+t.nicho+')_\n'; });
    msg += '\n';
  }
  if (d.driveLink) msg += '\ud83d\udcc4 '+d.driveLink;
  else msg += '\u26a0\ufe0f El PDF se gener\u00f3 pero no se subi\u00f3 a Drive (revisa credenciales)';
} else {
  msg = '\u274c Error generando tendencias: ' + (d.error || 'desconocido');
}
const CHATS = ['8100366018'];
return CHATS.map(chatId => ({ json: { chatId, mensaje: msg } }));
